changeSet.sql:
CREATE TABLE IF NOT EXISTS user_auth_provider (
    id SERIAL PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES "user"(id) ON DELETE CASCADE,
    provider VARCHAR(20) NOT NULL,
    provider_email VARCHAR(255) NOT NULL,
    linked_at TIMESTAMPTZ NOT NULL DEFAULT (CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),
    CONSTRAINT uq_user_auth_provider UNIQUE (user_id, provider)
);

CREATE INDEX IF NOT EXISTS idx_user_auth_provider_user_id ON user_auth_provider (user_id);

COMMENT ON TABLE user_auth_provider IS 'Tracks linked authentication providers for each user (LOCAL, GOOGLE, GITHUB)';
COMMENT ON COLUMN user_auth_provider.id IS 'Unique identifier for the auth provider record';
COMMENT ON COLUMN user_auth_provider.user_id IS 'Reference to the user who owns this provider link';
COMMENT ON COLUMN user_auth_provider.provider IS 'Authentication provider type (LOCAL, GOOGLE, GITHUB)';
COMMENT ON COLUMN user_auth_provider.provider_email IS 'Email address associated with this provider';
COMMENT ON COLUMN user_auth_provider.linked_at IS 'Timestamp when this provider was linked';
COMMENT ON INDEX idx_user_auth_provider_user_id IS 'Index for finding all providers for a given user';
COMMENT ON COLUMN "user".has_password IS 'Whether the user has a real password set (false for OAuth2-only users)';
